const html = $input.first().json.body || $input.first().json.data || '';
const strip = (s) => String(s || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
const titleMatch = html.match(/<h1[^>]*>([\s\S]*?)<\/h1>/i);
const articleTitle = titleMatch ? strip(titleMatch[1]) : 'מדריך מקיף לבחירה ושימוש באנקודרים סיבוביים בתעשייה';
const articleMatch = html.match(/<article[^>]*>([\s\S]*?)<\/article>/i) || html.match(/<main[^>]*>([\s\S]*?)<\/main>/i);
const articleBody = articleMatch ? articleMatch[1] : html;
const sections = [];
const h2Regex = /<h2[^>]*(?:id=["']([^"']+)["'])?[^>]*>([\s\S]*?)<\/h2>([\s\S]*?)(?=<h2|<\/article|<\/main|$)/gi;
let match;
while ((match = h2Regex.exec(articleBody)) !== null) {
  const heading = strip(match[2]);
  const content = match[3].trim();
  if (heading && strip(content).length > 40) sections.push({id: match[1] || `section-${sections.length + 1}`, heading, content});
}
const images = [];
const imgRegex = /<img[^>]+src=["']([^"']+)["'][^>]*>/gi;
let img;
while ((img = imgRegex.exec(html)) !== null) {
  if (img[1].includes('mapril.websmail.net') && !images.includes(img[1])) images.push(img[1]);
}
const fallbackImages = [
  'https://mapril.websmail.net/wp-content/uploads/2026/04/WhatistheDifferenceBetweenanIncrementalEncoderandanAbsoluteEncoder-scaled.jpg',
  'https://mapril.websmail.net/wp-content/uploads/2026/04/ParameterComparisonWhattoCheckBeforeOrderinganEncoder.jpg',
  'https://mapril.websmail.net/wp-content/uploads/2026/04/WhatDoYouActuallyGetWhenChoosinganEncoderfromGalozElectronics.jpg'
];
const links = [...html.matchAll(/href=["']([^"']*galoz\.co\.il[^"']*)["']/gi)].map(m => m[1]);
return [{json: {articleTitle, articleBody, sections, articleImages: images.length ? images : fallbackImages, galozLinks: [...new Set(links)], sourceUrl: 'https://mapril.websmail.net/industrial-rotary-encoder-sensors-2/', targetKeyword: 'אנקודר סיבובי', secondaryKeywords: ['אנקודרים', 'PPR', 'אנקודר אינקרמנטלי', 'אנקודר אבסולוטי', 'רמת אטימות IP', 'Push-Pull', 'Line Driver'], processedAt: new Date().toISOString()}}];

