const aiResponse = $input.first().json;
const sourceData = $('Parse Article Sections').first().json;
let articleData;
try {
  const content = aiResponse.message?.content || aiResponse.choices?.[0]?.message?.content || aiResponse.text || JSON.stringify(aiResponse);
  articleData = typeof content === 'string' ? JSON.parse(content) : content;
} catch (error) {
  articleData = {
    title: sourceData.articleTitle,
    introParagraphs: [
      'אנקודר סיבובי מספק למערכת הבקרה משוב על מיקום, מהירות וכיוון סיבוב, ולכן הוא משפיע ישירות על דיוק ואמינות המכונה.',
      'בחירה נכונה מתחילה בהגדרת היישום, תנאי הסביבה, דרישות הרזולוציה וסוג היציאה החשמלית.'
    ],
    takeaways: ['להגדיר סוג אנקודר לפני מחיר', 'לאזן בין PPR ליכולת הבקר', 'להתאים IP לסביבת העבודה', 'לוודא התאמת יציאה חשמלית', 'להיעזר בליווי טכני לפני הזמנה'],
    sections: sourceData.sections,
    faqItems: [
      {q: 'מה זה אנקודר סיבובי?', a: 'חיישן שממיר תנועה זוויתית לאותות חשמליים עבור מערכת הבקרה.'},
      {q: 'מה ההבדל בין אינקרמנטלי לאבסולוטי?', a: 'אינקרמנטלי מודד שינוי ביחס לנקודת אפס; אבסולוטי שומר מיקום גם לאחר כיבוי.'},
      {q: 'כמה PPR צריך?', a: 'בהתאם לדיוק הנדרש, מהירות הסיבוב ויכולת הקריאה של הבקר.'}
    ]
  };
}
return [{json: {...sourceData, articleData, parsedAt: new Date().toISOString()}}];

const data = $input.first().json;
const brand = {name: 'גלעוז אלקטרוניקה', logo: 'https://d3m9l0v76dty0.cloudfront.net/system/logos/7002/original/f2a1fcfa083f4d83b3269684e5fe223e.png', contact: 'https://www.galoz.co.il/contact', email: 'sales@galoz.co.il'};
const title = data.articleData.title || data.articleTitle;
const intro = Array.isArray(data.articleData.introParagraphs) ? data.articleData.introParagraphs : [data.articleData.intro || ''];
const esc = (s) => String(s || '').replace(/[&<>]/g, ch => ({'&':'&amp;','<':'&lt;','>':'&gt;'}[ch]));
let html = `<!DOCTYPE html><html lang="he" dir="rtl"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1"><link href="https://fonts.googleapis.com/css2?family=Heebo:wght@400;500;600;700;800&display=swap" rel="stylesheet"><title>${esc(title)} | גלעוז אלקטרוניקה</title></head><body style="margin:0;padding:0;background:#eef4f8;color:#334155;font-family:'Heebo',Arial,sans-serif;line-height:1.75;direction:rtl;text-align:right;"><article style="max-width:1120px;margin:0 auto;padding:24px 16px 104px;box-sizing:border-box;"><section style="border:1px solid #d9e6ef;border-radius:24px;background:#fff;padding:28px 24px;margin:0 0 28px;box-shadow:0 18px 46px rgba(31,45,61,.10);"><img src="${brand.logo}" alt="גלעוז אלקטרוניקה" style="max-width:180px;height:auto;margin:0 0 18px;"><h1 style="margin:0 0 16px;color:#1F2D3D;font-size:clamp(2rem,4.6vw,3.4rem);line-height:1.12;">${esc(title)}</h1>${intro.map(p => `<p style="margin:0 0 14px;font-size:1.08rem;">${esc(p)}</p>`).join('')}<a href="${brand.contact}" style="display:inline-block;margin-top:8px;padding:12px 22px;border-radius:12px;background:#005696;color:#fff;text-decoration:none;font-weight:800;">לקבלת ייעוץ טכני</a></section>`;
html += `<details style="margin:0 0 28px;border:1px solid #d9e6ef;border-radius:18px;background:#fff;overflow:hidden;"><summary style="cursor:pointer;padding:18px 20px;background:#f8fafc;color:#1F2D3D;font-weight:800;">תוכן עניינים +</summary><nav style="padding:16px 20px;"><ol style="margin:0;padding-right:22px;">${(data.articleData.sections || []).slice(0,8).map((s,i)=>`<li style="margin:0 0 8px;"><a href="#section-${i+1}" style="color:#005696;text-decoration:none;font-weight:700;">${esc(s.heading || s.title || `סעיף ${i+1}`)}</a></li>`).join('')}</ol></nav></details>`;
(data.articleData.sections || []).slice(0,10).forEach((s,i) => { html += `<section id="section-${i+1}" style="margin:0 0 30px;padding:24px;border:1px solid #d9e6ef;border-radius:20px;background:#fff;box-shadow:0 10px 28px rgba(31,45,61,.06);"><h2 style="margin:0 0 14px;color:#1F2D3D;font-size:clamp(1.45rem,3vw,2rem);border-bottom:2px solid #005696;padding-bottom:10px;">${esc(s.heading || s.title)}</h2><div style="color:#334155;">${s.content || s.text || ''}</div></section>`; });
html += `<section style="margin:0 0 30px;padding:24px;border:1px solid #d9e6ef;border-radius:20px;background:#f8fafc;"><h2 style="margin:0 0 14px;color:#1F2D3D;">קישורים רלוונטיים בגלעוז</h2><p><a href="https://www.galoz.co.il/627671-%D7%90%D7%A0%D7%A7%D7%95%D7%93%D7%A8%D7%99%D7%9D" style="color:#005696;font-weight:800;">קטגוריית אנקודרים</a></p><p><a href="https://www.galoz.co.il/items/7805059-758-%D7%90%D7%A0%D7%A7%D7%95%D7%93%D7%A8-%D7%A8%D7%95%D7%91%D7%95%D7%A1%D7%98%D7%99-%D7%A2%D7%93-30-000-%D7%A4%D7%95%D7%9C%D7%A1%D7%99%D7%9D-%D7%9C%D7%A1%D7%99%D7%91%D7%95%D7%91-BEC" style="color:#005696;font-weight:800;">אנקודר רובוסטי BEC עד 30,000 פולסים לסיבוב</a></p></section>`;
html += `<section id="faq" style="margin:0 0 30px;padding:24px;border:1px solid #d9e6ef;border-radius:20px;background:#fff;"><h2 style="margin:0 0 14px;color:#1F2D3D;">שאלות נפוצות</h2>${(data.articleData.faqItems || []).map(f => `<details style="margin:0 0 12px;border:1px solid #d9e6ef;border-radius:14px;overflow:hidden;"><summary style="cursor:pointer;padding:16px 18px;background:#f8fafc;font-weight:800;">${esc(f.q)}</summary><div style="padding:16px 18px;border-top:1px solid #d9e6ef;"><p style="margin:0;">${esc(f.a)}</p></div></details>`).join('')}</section>`;
html += `<section style="padding:24px;border:1px solid #d9e6ef;border-radius:20px;background:#fff;"><h2 style="margin:0 0 12px;color:#1F2D3D;">צוות גלעוז אלקטרוניקה</h2><p style="margin:0 0 14px;">גלעוז אלקטרוניקה מתמחה מעל 30 שנה בפתרונות פיקוד, בקרה ומדידה לתעשייה.</p><a href="${brand.contact}" style="color:#005696;font-weight:800;">יצירת קשר</a> | <a href="mailto:${brand.email}" style="color:#005696;font-weight:800;">${brand.email}</a></section><script type="application/ld+json">{"@context":"https://schema.org","@type":"Article","headline":"${esc(title)}","inLanguage":"he-IL","mainEntityOfPage":"${data.sourceUrl}","author":{"@type":"Organization","name":"גלעוז אלקטרוניקה"}}</script></article></body></html>`;
const h1Count = (html.match(/<h1\b/gi) || []).length;
return [{json: {html, h1Count, sourceUrl: data.sourceUrl, targetKeyword: data.targetKeyword, generatedAt: new Date().toISOString()}}];

const item = $input.first().json;
const html = item.html || '';
const failures = [];
if (item.h1Count !== 1) failures.push('HTML must contain exactly one H1');
if (!html.includes('dir="rtl"')) failures.push('Missing RTL direction');
if (html.includes('<style')) failures.push('Inline-only mode forbids style blocks');
if (/src=["']\s*["']/.test(html)) failures.push('Empty image src found');
if (!html.includes('https://mapril.websmail.net/industrial-rotary-encoder-sensors-2/')) failures.push('Source URL not synchronized');
if (!html.includes('אנקודר')) failures.push('Encoder topic missing');
if (!html.includes('https://www.galoz.co.il/contact')) failures.push('Galoz contact URL missing');
return [{json: {...item, qualityPassed: failures.length === 0, failures}}];
